// pages/SelectAddressPage.jsx
//
// Route (React Router v6):
//   <Route path="/select-address" element={<SelectAddressPage />} />
//
// No API key needed — uses:
//   • Leaflet (OSM tiles) for the map
//   • Nominatim (OSM) for reverse geocoding
//   • Open-Elevation API for altitude
//
// On confirm, calls onConfirm({ lat, lng, altitude, address }) or
// navigates back with location state if used standalone.

import { useState, useEffect, useRef, useCallback } from "react";
import { useNavigate } from "react-router-dom";

// ── Leaflet is loaded via CDN tags injected once ──────────────────
function ensureLeaflet() {
  return new Promise((resolve) => {
    if (window.L) { resolve(window.L); return; }

    const css = document.createElement("link");
    css.rel  = "stylesheet";
    css.href = "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.css";
    document.head.appendChild(css);

    const script = document.createElement("script");
    script.src = "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.js";
    script.onload = () => resolve(window.L);
    document.head.appendChild(script);
  });
}

// ── Reverse geocode via Nominatim ─────────────────────────────────
async function reverseGeocode(lat, lng) {
  try {
    const r = await fetch(
      `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json`,
      { headers: { "Accept-Language": "en" } }
    );
    const d = await r.json();
    return d.display_name ?? `${lat.toFixed(5)}, ${lng.toFixed(5)}`;
  } catch {
    return `${lat.toFixed(5)}, ${lng.toFixed(5)}`;
  }
}

// ── Altitude via Open-Elevation ───────────────────────────────────
async function fetchAltitude(lat, lng) {
  try {
    const r = await fetch(
      `https://api.open-elevation.com/api/v1/lookup?locations=${lat},${lng}`
    );
    const d = await r.json();
    return d.results?.[0]?.elevation ?? null;
  } catch {
    return null;
  }
}

// ── Tiny spinner SVG ──────────────────────────────────────────────
function Spinner({ size = 16, color = "#FF6B9D" }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none"
      stroke={color} strokeWidth={2.5} strokeLinecap="round"
      style={{ animation: "spin 0.8s linear infinite", flexShrink: 0 }}>
      <path d="M12 2a10 10 0 1 0 10 10" />
    </svg>
  );
}

// ── Coordinate pill ───────────────────────────────────────────────
function CoordPill({ label, value, accent }) {
  return (
    <div style={{
      display: "flex", flexDirection: "column", alignItems: "center",
      background: `${accent}14`, border: `1px solid ${accent}40`,
      borderRadius: 14, padding: "10px 18px", minWidth: 100,
    }}>
      <span style={{
        fontFamily: "'Nunito',sans-serif", fontWeight: 700,
        fontSize: "0.65rem", color: `${accent}99`,
        textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: 4,
      }}>{label}</span>
      <span style={{
        fontFamily: "'Space Mono',monospace", fontWeight: 700,
        fontSize: "0.82rem", color: "#fff",
      }}>
        {value !== null && value !== undefined ? value : "—"}
      </span>
    </div>
  );
}

// ── Main Page ─────────────────────────────────────────────────────
export default function SelectAddressPage({ onConfirm }) {
  const navigate   = useNavigate();
  const mapRef     = useRef(null);   // DOM node
  const leafletMap = useRef(null);   // L.Map instance
  const markerRef  = useRef(null);   // L.Marker instance

  const [coords,   setCoords]   = useState(null);      // { lat, lng }
  const [altitude, setAltitude] = useState(null);      // metres | null
  const [address,  setAddress]  = useState("");
  const [geocoding, setGeocoding] = useState(false);
  const [elevating, setElevating] = useState(false);
  const [confirmed, setConfirmed] = useState(false);
  const [mounted,   setMounted]   = useState(false);

  // Debounce ref for geocoding
  const geocodeTimer = useRef(null);

  // ── Update info panel when pin moves ───────────────────────────
  const onPinMove = useCallback(async (lat, lng) => {
    setCoords({ lat, lng });
    setAltitude(null);
    setAddress("");

    // Debounce geocode (300 ms)
    clearTimeout(geocodeTimer.current);
    setGeocoding(true);
    geocodeTimer.current = setTimeout(async () => {
      const [addr, alt] = await Promise.all([
        reverseGeocode(lat, lng),
        (setElevating(true), fetchAltitude(lat, lng)),
      ]);
      setAddress(addr);
      setGeocoding(false);
      setAltitude(alt);
      setElevating(false);
    }, 300);
  }, []);

  // ── Init Leaflet once ───────────────────────────────────────────
  useEffect(() => {
    let cancelled = false;
    setTimeout(() => setMounted(true), 60);

    ensureLeaflet().then((L) => {
      if (cancelled || leafletMap.current) return;

      // Default to New Delhi
      const defaultLat = 28.6139;
      const defaultLng = 77.2090;

      const map = L.map(mapRef.current, {
        center: [defaultLat, defaultLng],
        zoom: 15,
        zoomControl: false,
      });

      L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
        attribution: "© OpenStreetMap contributors",
        maxZoom: 19,
      }).addTo(map);

      // Custom pink pin icon
      const pinIcon = L.divIcon({
        className: "",
        html: `
          <div style="
            position:relative;
            width:36px; height:46px;
            filter: drop-shadow(0 6px 18px rgba(255,61,127,0.7));
            animation: pinDrop 0.5s cubic-bezier(.34,1.56,.64,1) both;
          ">
            <svg viewBox="0 0 36 46" width="36" height="46" xmlns="http://www.w3.org/2000/svg">
              <defs>
                <radialGradient id="pinGrad" cx="38%" cy="32%" r="65%">
                  <stop offset="0%" stop-color="#FF6B9D"/>
                  <stop offset="100%" stop-color="#FF3D7F"/>
                </radialGradient>
              </defs>
              <path d="M18 2C9.716 2 3 8.716 3 17c0 10.5 15 27 15 27s15-16.5 15-27c0-8.284-6.716-15-15-15z"
                fill="url(#pinGrad)" stroke="#fff" stroke-width="1.5"/>
              <circle cx="18" cy="17" r="6" fill="#fff" opacity="0.9"/>
              <circle cx="18" cy="17" r="3" fill="#FF3D7F"/>
            </svg>
          </div>`,
        iconSize:   [36, 46],
        iconAnchor: [18, 46],
      });

      const marker = L.marker([defaultLat, defaultLng], {
        icon:      pinIcon,
        draggable: true,
      }).addTo(map);

      marker.on("dragend", (e) => {
        const { lat, lng } = e.target.getLatLng();
        onPinMove(lat, lng);
      });

      // Click on map moves pin
      map.on("click", (e) => {
        marker.setLatLng(e.latlng);
        onPinMove(e.latlng.lat, e.latlng.lng);
      });

      leafletMap.current = map;
      markerRef.current  = marker;

      // Init info for default position
      onPinMove(defaultLat, defaultLng);
    });

    // Try to get user's actual location
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((pos) => {
        const { latitude: lat, longitude: lng } = pos.coords;
        if (leafletMap.current && markerRef.current && !cancelled) {
          leafletMap.current.setView([lat, lng], 16);
          markerRef.current.setLatLng([lat, lng]);
          onPinMove(lat, lng);
        }
      }, () => {/* ignore denial */});
    }

    return () => {
      cancelled = true;
      clearTimeout(geocodeTimer.current);
      if (leafletMap.current) {
        leafletMap.current.remove();
        leafletMap.current = null;
      }
    };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // ── Confirm ─────────────────────────────────────────────────────
  const handleConfirm = () => {
    if (!coords) return;
    setConfirmed(true);
    const payload = {
      lat:      parseFloat(coords.lat.toFixed(6)),
      lng:      parseFloat(coords.lng.toFixed(6)),
      altitude: altitude,
      address,
    };
    if (typeof onConfirm === "function") {
      onConfirm(payload);
    } else {
      navigate(-1, { state: { selectedLocation: payload } });
    }
  };

  const ACCENT = "#FF6B9D";

  return (
    <div style={{
      minHeight: "100vh", display: "flex", flexDirection: "column",
      background: "linear-gradient(160deg,#0a0814 0%,#110d24 55%,#08101e 100%)",
      fontFamily: "'Nunito',sans-serif", color: "#fff",
      position: "relative", overflowX: "hidden",
      opacity: mounted ? 1 : 0, transition: "opacity 0.4s ease",
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;600;700;800;900&family=Space+Mono:wght@700&display=swap');

        @keyframes spin       { to { transform: rotate(360deg); } }
        @keyframes pinDrop    {
          0%   { transform: translateY(-30px) scale(0.7); opacity:0; }
          70%  { transform: translateY(4px) scale(1.1); }
          100% { transform: translateY(0) scale(1); opacity:1; }
        }
        @keyframes slideUp {
          0%   { opacity:0; transform: translateY(24px); }
          100% { opacity:1; transform: translateY(0); }
        }
        @keyframes headerIn {
          0%   { opacity:0; transform: translateY(-14px); }
          100% { opacity:1; transform: translateY(0); }
        }
        @keyframes confirmPop {
          0%   { transform: scale(0.92); opacity:0; }
          60%  { transform: scale(1.04); }
          100% { transform: scale(1); opacity:1; }
        }

        /* Override Leaflet attribution to match dark theme */
        .leaflet-control-attribution {
          background: rgba(10,8,20,0.75) !important;
          color: rgba(255,255,255,0.35) !important;
          font-size: 10px !important;
          backdrop-filter: blur(6px);
          border-radius: 6px 0 0 0 !important;
        }
        .leaflet-control-attribution a { color: rgba(255,107,157,0.7) !important; }

        /* Pulse ring under pin while dragging */
        .leaflet-marker-dragging .pin-pulse {
          animation: pulsering 0.6s ease-in-out infinite !important;
        }
        @keyframes pulsering {
          0%,100% { transform: scale(1); opacity:0.6; }
          50%      { transform: scale(1.4); opacity:0; }
        }

        * { box-sizing: border-box; }
        ::-webkit-scrollbar { width: 5px; }
        ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 3px; }
      `}</style>

      {/* ── Ambient blobs ── */}
      <div style={{ position:"fixed", top:-100, right:-100, width:480, height:480, borderRadius:"50%", background:"radial-gradient(circle,rgba(255,107,157,0.12) 0%,transparent 70%)", pointerEvents:"none", zIndex:0 }} />
      <div style={{ position:"fixed", bottom:-60, left:-60, width:360, height:360, borderRadius:"50%", background:"radial-gradient(circle,rgba(204,93,232,0.08) 0%,transparent 70%)", pointerEvents:"none", zIndex:0 }} />

      {/* ── Sticky header ── */}
      <div style={{
        position: "sticky", top: 0, zIndex: 1000,
        background: "rgba(10,8,20,0.90)", backdropFilter: "blur(20px)",
        borderBottom: "1px solid rgba(255,255,255,0.07)",
        padding: "0 20px",
        animation: "headerIn 0.4s ease both",
      }}>
        <div style={{ maxWidth: 700, margin: "0 auto", padding: "14px 0 12px", display: "flex", alignItems: "center", gap: 14 }}>
          <button
            onClick={() => navigate(-1)}
            style={{
              background: "rgba(255,255,255,0.06)", border: "1px solid rgba(255,255,255,0.1)",
              borderRadius: 11, padding: "8px 13px", color: "rgba(255,255,255,0.6)",
              cursor: "pointer", fontFamily: "'Nunito',sans-serif", fontWeight: 700, fontSize: "0.82rem",
              display: "flex", alignItems: "center", gap: 5, transition: "all 0.2s", flexShrink: 0,
            }}
            onMouseEnter={e => { e.currentTarget.style.background = "rgba(255,255,255,0.1)"; e.currentTarget.style.color = "#fff"; }}
            onMouseLeave={e => { e.currentTarget.style.background = "rgba(255,255,255,0.06)"; e.currentTarget.style.color = "rgba(255,255,255,0.6)"; }}
          >
            <svg width={13} height={13} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.5} strokeLinecap="round">
              <path d="M19 12H5M12 5l-7 7 7 7"/>
            </svg>
            Back
          </button>

          <div style={{ flex: 1, display: "flex", alignItems: "center", gap: 10 }}>
            <span style={{ fontSize: "1.35rem" }}>📍</span>
            <h1 style={{
              margin: 0, fontFamily: "'Nunito',sans-serif", fontWeight: 900,
              fontSize: "clamp(1rem,3vw,1.3rem)",
              background: "linear-gradient(135deg,#FF6B9D,#CC5DE8)",
              WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
            }}>Select Delivery Address</h1>
          </div>

          <div style={{
            background: "rgba(255,107,157,0.1)", border: "1px solid rgba(255,107,157,0.25)",
            borderRadius: 10, padding: "5px 12px",
            fontFamily: "'Nunito',sans-serif", fontWeight: 700, fontSize: "0.72rem",
            color: "rgba(255,107,157,0.8)",
          }}>
            Drag or tap to place
          </div>
        </div>
      </div>

      {/* ── Map container ── */}
      <div style={{ position: "relative", flex: 1, minHeight: 0 }}>
        <div ref={mapRef} style={{ width: "100%", height: "100%", minHeight: "55vh" }} />

        {/* Crosshair hint overlay — fades out after mount */}
        <div style={{
          position: "absolute", inset: 0, pointerEvents: "none", zIndex: 500,
          display: "flex", alignItems: "center", justifyContent: "center",
        }}>
          {/* subtle vignette */}
          <div style={{
            position: "absolute", inset: 0,
            background: "radial-gradient(ellipse at center, transparent 45%, rgba(10,8,20,0.35) 100%)",
          }} />
        </div>

        {/* "You are here" locate button */}
        <button
          title="Use my location"
          onClick={() => {
            if (!navigator.geolocation) return;
            navigator.geolocation.getCurrentPosition((pos) => {
              const { latitude: lat, longitude: lng } = pos.coords;
              if (leafletMap.current && markerRef.current) {
                leafletMap.current.setView([lat, lng], 17, { animate: true });
                markerRef.current.setLatLng([lat, lng]);
                onPinMove(lat, lng);
              }
            });
          }}
          style={{
            position: "absolute", bottom: 20, right: 16, zIndex: 800,
            width: 44, height: 44, borderRadius: 13, border: "1px solid rgba(255,255,255,0.15)",
            background: "rgba(10,8,20,0.85)", backdropFilter: "blur(12px)",
            color: "#fff", cursor: "pointer",
            display: "flex", alignItems: "center", justifyContent: "center",
            boxShadow: "0 4px 20px rgba(0,0,0,0.5)",
            transition: "all 0.2s",
          }}
          onMouseEnter={e => { e.currentTarget.style.background = "rgba(255,107,157,0.2)"; e.currentTarget.style.borderColor = "rgba(255,107,157,0.4)"; }}
          onMouseLeave={e => { e.currentTarget.style.background = "rgba(10,8,20,0.85)"; e.currentTarget.style.borderColor = "rgba(255,255,255,0.15)"; }}
        >
          <svg width={18} height={18} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} strokeLinecap="round">
            <circle cx={12} cy={12} r={3}/>
            <path d="M12 2v3M12 19v3M2 12h3M19 12h3"/>
            <circle cx={12} cy={12} r={9} strokeOpacity={0.3}/>
          </svg>
        </button>

        {/* Zoom controls */}
        <div style={{
          position: "absolute", bottom: 72, right: 16, zIndex: 800,
          display: "flex", flexDirection: "column", gap: 2,
        }}>
          {["+", "−"].map((label, i) => (
            <button key={i}
              onClick={() => {
                if (!leafletMap.current) return;
                i === 0 ? leafletMap.current.zoomIn() : leafletMap.current.zoomOut();
              }}
              style={{
                width: 44, height: 44, borderRadius: i === 0 ? "11px 11px 4px 4px" : "4px 4px 11px 11px",
                border: "1px solid rgba(255,255,255,0.12)",
                background: "rgba(10,8,20,0.85)", backdropFilter: "blur(12px)",
                color: "#fff", cursor: "pointer", fontSize: "1.3rem", fontWeight: 300,
                display: "flex", alignItems: "center", justifyContent: "center",
                boxShadow: "0 4px 20px rgba(0,0,0,0.4)",
                transition: "all 0.2s",
              }}
              onMouseEnter={e => e.currentTarget.style.background = "rgba(255,107,157,0.18)"}
              onMouseLeave={e => e.currentTarget.style.background = "rgba(10,8,20,0.85)"}
            >{label}</button>
          ))}
        </div>
      </div>

      {/* ── Info + confirm panel ── */}
      <div style={{
        background: "rgba(10,8,20,0.94)", backdropFilter: "blur(24px)",
        borderTop: "1px solid rgba(255,255,255,0.07)",
        padding: "20px 20px 28px",
        animation: "slideUp 0.5s cubic-bezier(.34,1.56,.64,1) 0.15s both",
        zIndex: 900, position: "relative",
      }}>
        <div style={{ maxWidth: 700, margin: "0 auto" }}>

          {/* Coordinate pills */}
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap", marginBottom: 16, justifyContent: "center" }}>
            <CoordPill
              label="Latitude"
              value={coords ? coords.lat.toFixed(6) : null}
              accent="#FF6B9D"
            />
            <CoordPill
              label="Longitude"
              value={coords ? coords.lng.toFixed(6) : null}
              accent="#CC5DE8"
            />
            <CoordPill
              label={elevating ? "Altitude…" : "Altitude (m)"}
              value={elevating ? null : altitude !== null ? `${altitude} m` : null}
              accent="#38D9A9"
            />
          </div>

          {/* Address row */}
          <div style={{
            display: "flex", alignItems: "flex-start", gap: 10,
            background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.08)",
            borderRadius: 16, padding: "13px 16px", marginBottom: 18, minHeight: 52,
          }}>
            {geocoding
              ? <Spinner size={16} color="#FF6B9D" />
              : <svg width={16} height={16} viewBox="0 0 24 24" fill="none" stroke="#FF6B9D" strokeWidth={2} strokeLinecap="round" style={{ flexShrink:0, marginTop:1 }}>
                  <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx={12} cy={10} r={3}/>
                </svg>
            }
            <p style={{
              margin: 0, fontFamily: "'Nunito',sans-serif", fontWeight: 600,
              fontSize: "0.83rem", color: geocoding ? "rgba(255,255,255,0.3)" : "rgba(255,255,255,0.75)",
              lineHeight: 1.45, flex: 1,
            }}>
              {geocoding ? "Fetching address…" : address || "Move the pin to select a location"}
            </p>
          </div>

          {/* Confirm button */}
          <button
            onClick={handleConfirm}
            disabled={!coords || geocoding || confirmed}
            style={{
              width: "100%", padding: "15px 24px", border: "none", borderRadius: 16,
              fontFamily: "'Nunito',sans-serif", fontWeight: 900, fontSize: "1rem",
              letterSpacing: "0.04em",
              background: (!coords || geocoding || confirmed)
                ? "rgba(255,255,255,0.07)"
                : "linear-gradient(135deg,#FF6B9D,#CC5DE8)",
              color: (!coords || geocoding || confirmed)
                ? "rgba(255,255,255,0.3)"
                : "#fff",
              cursor: (!coords || geocoding || confirmed) ? "not-allowed" : "pointer",
              boxShadow: (!coords || geocoding || confirmed)
                ? "none"
                : "0 8px 32px rgba(255,61,127,0.4)",
              transition: "all 0.3s cubic-bezier(.34,1.56,.64,1)",
              display: "flex", alignItems: "center", justifyContent: "center", gap: 10,
              animation: coords && !geocoding ? "confirmPop 0.4s cubic-bezier(.34,1.56,.64,1) both" : "none",
            }}
            onMouseEnter={e => {
              if (coords && !geocoding && !confirmed) {
                e.currentTarget.style.transform = "scale(1.02)";
                e.currentTarget.style.boxShadow = "0 12px 40px rgba(255,61,127,0.55)";
              }
            }}
            onMouseLeave={e => {
              e.currentTarget.style.transform = "scale(1)";
              e.currentTarget.style.boxShadow = (!coords || geocoding || confirmed)
                ? "none"
                : "0 8px 32px rgba(255,61,127,0.4)";
            }}
          >
            {confirmed ? (
              <>
                <svg width={18} height={18} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.5} strokeLinecap="round">
                  <polyline points="20 6 9 17 4 12"/>
                </svg>
                Address Confirmed!
              </>
            ) : (
              <>
                <svg width={18} height={18} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.2} strokeLinecap="round">
                  <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx={12} cy={10} r={3}/>
                </svg>
                Confirm This Location
              </>
            )}
          </button>

          {/* Helper hint */}
          {coords && (
            <p style={{
              margin: "12px 0 0", textAlign: "center",
              fontFamily: "'Nunito',sans-serif", fontWeight: 600,
              fontSize: "0.74rem", color: "rgba(255,255,255,0.22)",
            }}>
              Drag the pin or tap the map to adjust
            </p>
          )}
        </div>
      </div>
    </div>
  );
}
